import{bQ as i,aL as a,u as t,G as n}from"./chunks/framework.D06dwy5q.js";const c=JSON.parse('{"title":"01｜安装与连接","description":"","frontmatter":{},"headers":[],"relativePath":"04.MySQL/01-安装与连接.md","filePath":"04.MySQL/01-安装与连接.md","lastUpdated":null}'),l={name:"04.MySQL/01-安装与连接.md"};function h(p,s,e,k,d,r){return a(),t("div",null,[...s[0]||(s[0]=[n(`<h1 id="_01-安装与连接" tabindex="-1">01｜安装与连接 <a class="header-anchor" href="#_01-安装与连接" aria-label="Permalink to &quot;01｜安装与连接&quot;">​</a></h1><p>要在服务器上用 MySQL 存数据，第一件事是装一个 MySQL 实例让它跑起来。云上的 RDS 点几下就有了，但自己装一个，会踩到几个具体的坑：配了参数起不来、目录权限不对报错、启动后不知道初始密码。</p><p>本篇从零装一个 MySQL，把这些坑的位置讲清楚。当前生产推荐版本是 <strong>MySQL 8.4 LTS</strong>（8.0 已于 2026 年 4 月停止支持，5.7 更早）。</p><h2 id="一、两种安装方式" tabindex="-1">一、两种安装方式 <a class="header-anchor" href="#一、两种安装方式" aria-label="Permalink to &quot;一、两种安装方式&quot;">​</a></h2><p>装 MySQL 有两种主流方式：</p><table tabindex="0"><thead><tr><th>方式</th><th>特点</th><th>适合</th></tr></thead><tbody><tr><td>系统包安装</td><td>快，一行命令；版本跟系统仓库走</td><td>测试、快速试用</td></tr><tr><td>二进制包安装</td><td>版本自己掌控、路径统一、不依赖系统仓库</td><td>生产</td></tr></tbody></table><p>生产环境统一用二进制包——版本固定、升级时清楚换的是哪个版本。包安装的版本受系统仓库限制，可能装到老版本，升级也混乱。测试想快速跑起来可以用包安装。</p><h2 id="二、包安装-先跑起来" tabindex="-1">二、包安装：先跑起来 <a class="header-anchor" href="#二、包安装-先跑起来" aria-label="Permalink to &quot;二、包安装：先跑起来&quot;">​</a></h2><p>包安装最快。装之前先加 MySQL 官方仓库（系统自带的仓库版本可能旧）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># RHEL / Rocky</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://repo.mysql.com/mysql84-community-release-el9.rpm</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yum</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mysql-community-server</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Debian / Ubuntu</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;&amp; </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -y</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mysql-server</span></span></code></pre></div><p>装完，文件散落在系统各处。几个路径要记住，后面排查要用：</p><table tabindex="0"><thead><tr><th>路径</th><th>装什么</th></tr></thead><tbody><tr><td><code>/etc/my.cnf</code></td><td>配置入口</td></tr><tr><td><code>/var/lib/mysql</code></td><td>数据目录（存表、日志）</td></tr><tr><td><code>/var/log/mysqld.log</code></td><td>错误日志</td></tr></tbody></table><p>记不住用命令查安装了哪些文件：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rpm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -ql</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mysql-community-server</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # RHEL</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dpkg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mysql-server</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> head</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">             # Debian</span></span></code></pre></div><p>启动：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mysqld</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> enable</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mysqld</span></span></code></pre></div><p>包安装的 MySQL 首次启动时会自动初始化数据目录、生成一个临时 root 密码。去日志里找：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;temporary password&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/mysqld.log</span></span></code></pre></div><p>拿到这串密码，才能登录。</p><h2 id="三、二进制安装-生产的方式" tabindex="-1">三、二进制安装：生产的方式 <a class="header-anchor" href="#三、二进制安装-生产的方式" aria-label="Permalink to &quot;三、二进制安装：生产的方式&quot;">​</a></h2><p>生产用二进制包，版本和路径自己掌控。从 MySQL 官网下载 8.4 的二进制包（<code>mysql-8.4.x-linux-glibc2.28-x86_64.tar.xz</code>）。</p><h3 id="解压和建用户" tabindex="-1">解压和建用户 <a class="header-anchor" href="#解压和建用户" aria-label="Permalink to &quot;解压和建用户&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 解压</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -xf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mysql-8.4.x-linux-glibc2.28-x86_64.tar.xz</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -C</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/local/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ln</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/local/mysql-8.4.x-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /usr/local/mysql</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 建专用用户（MySQL 进程以这个身份跑，不需要人登录）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">groupadd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mysql</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">useradd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mysql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /sbin/nologin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mysql</span></span></code></pre></div><p>为什么建单独的 mysql 用户而不是用 root 跑？MySQL 是长期跑的服务，以 root 跑风险大——一旦 MySQL 被攻破，攻击者直接拿到 root。用低权限的 mysql 用户跑，就算被攻破也只能动 mysql 能动的文件。<code>-s /sbin/nologin</code> 让这个用户不能登录 shell，只是个进程身份。</p><h3 id="规划数据目录" tabindex="-1">规划数据目录 <a class="header-anchor" href="#规划数据目录" aria-label="Permalink to &quot;规划数据目录&quot;">​</a></h3><p>数据、日志、临时文件分开存，便于管理和备份：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /data/mysql/{data,logs,tmp}</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chown</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mysql:mysql</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /data/mysql</span></span></code></pre></div><p><code>/data</code> 和 <code>/var</code> 分开是常见做法——<code>/var</code> 可能和系统盘在一起，<code>/data</code> 单独挂盘，数据盘满了不影响系统。</p><h3 id="初始化数据目录" tabindex="-1">初始化数据目录 <a class="header-anchor" href="#初始化数据目录" aria-label="Permalink to &quot;初始化数据目录&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/usr/local/mysql/bin/mysqld</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --initialize</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --user=mysql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --basedir=/usr/local/mysql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    --datadir=/data/mysql/data</span></span></code></pre></div><p>这个命令建系统表、生成初始 root 密码（输出在屏幕上，或写到错误日志）。<strong>这个命令只在第一次执行——重新跑一次会让已有数据全部丢失。</strong> 临时密码形如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A temporary password is generated for root@localhost: xQwe9_abcDkL</span></span></code></pre></div><p>记下这串，等下登录用。</p><h2 id="四、配置文件" tabindex="-1">四、配置文件 <a class="header-anchor" href="#四、配置文件" aria-label="Permalink to &quot;四、配置文件&quot;">​</a></h2><p>MySQL 启动时读配置文件。二进制安装的配置文件放 <code>/etc/my.cnf</code>：</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># /etc/my.cnf</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[mysqld]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">server_id</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">port</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=3306</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">user</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=mysql</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">basedir</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/usr/local/mysql</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">datadir</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/data/mysql/data</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">socket</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/data/mysql/tmp/mysql.sock</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">pid-file</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/data/mysql/tmp/mysqld.pid</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">log_error</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/data/mysql/logs/error.log</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">character_set_server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=utf8mb4</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">collation_server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=utf8mb4_0900_ai_ci</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">max_connections</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=500</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">innodb_buffer_pool_size</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=1G</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">log_bin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/data/mysql/logs/mysql-bin</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">binlog_format</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=ROW</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">binlog_expire_logs_seconds</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=604800</span></span></code></pre></div><p>几个容易踩的参数单独说：</p><p><strong><code>character_set_server=utf8mb4</code></strong>——别写成 <code>utf8</code>。MySQL 里的 <code>utf8</code> 是残缺的，最多存 3 字节，存 emoji（😊，4 字节）会报错。<code>utf8mb4</code> 才是完整的 UTF-8。新装的库一定要用 utf8mb4，否则后面存 emoji 时才发现要改字符集，很麻烦。</p><p><strong><code>innodb_buffer_pool_size</code></strong>——InnoDB 把热数据缓存在内存里，这块大小直接决定查询是从内存取（快）还是读磁盘（慢）。一般给到机器可用内存的 60%-70%。给小了查询慢，给大了挤占系统其他进程。</p><p><strong><code>log_bin</code> + <code>binlog_format=ROW</code></strong>——开启 binlog 才能做时间点恢复和主从复制。<code>ROW</code> 格式记录每行数据的变化，比老的 <code>STATEMENT</code> 格式精确，是现在的主推。</p><h3 id="改配置的风险" tabindex="-1">改配置的风险 <a class="header-anchor" href="#改配置的风险" aria-label="Permalink to &quot;改配置的风险&quot;">​</a></h3><p>MySQL 没有 <code>nginx -t</code> 那种配置检查命令。改完配置只能通过重启验证。生产改配置前必须备份旧文件，在低峰窗口重启：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/my.cnf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/my.cnf.bak.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">date</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +%F</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="五、启动和第一次登录" tabindex="-1">五、启动和第一次登录 <a class="header-anchor" href="#五、启动和第一次登录" aria-label="Permalink to &quot;五、启动和第一次登录&quot;">​</a></h2><p>二进制安装要手动启动（或写 systemd unit，这里先手动跑通）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/usr/local/mysql/bin/mysqld_safe</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user=mysql</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &amp;</span></span></code></pre></div><p>用临时密码登录：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mysql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -uroot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span></span></code></pre></div><p>输临时密码进去。第一件事改密码：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">ALTER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> USER</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;root&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;localhost&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> IDENTIFIED </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">BY</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;你的新密码&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>8.4 默认密码策略要求高强度——大小写+数字+特殊字符+一定长度。设太简单会报错 <code>Your password does not satisfy the current policy requirements</code>。</p><h2 id="六、几个日志各管各的" tabindex="-1">六、几个日志各管各的 <a class="header-anchor" href="#六、几个日志各管各的" aria-label="Permalink to &quot;六、几个日志各管各的&quot;">​</a></h2><p>第一次接触 MySQL 会被一堆&quot;xx log&quot;搞晕。它们是不同的人记不同的账：</p><table tabindex="0"><thead><tr><th>日志</th><th>记什么</th><th>什么时候用</th></tr></thead><tbody><tr><td>错误日志（error log）</td><td>启动失败、崩溃恢复、连接被拒、复制断了</td><td>排查问题的第一站</td></tr><tr><td>binlog</td><td>每一笔数据变更</td><td>主从复制、时间点恢复</td></tr><tr><td>redo log（InnoDB 内部）</td><td>改过的页还没刷回磁盘</td><td>崩溃恢复，自动的，不用碰</td></tr><tr><td>undo log（InnoDB 内部）</td><td>修改前的老数据</td><td>事务回滚、MVCC，自动的</td></tr></tbody></table><p>日常最常用前两个：错误日志排查问题、binlog 做恢复。redo 和 undo 是 InnoDB 自己维护的，运维一般不直接操作，知道它们存在就行。</p><p>错误日志路径在配置里写的 <code>/data/mysql/logs/error.log</code>，启动失败先看它：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /data/mysql/logs/error.log</span></span></code></pre></div><h2 id="七、客户端连接" tabindex="-1">七、客户端连接 <a class="header-anchor" href="#七、客户端连接" aria-label="Permalink to &quot;七、客户端连接&quot;">​</a></h2><p>本机连接用 socket（不走网络，最快）：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mysql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -uroot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span></span></code></pre></div><p>不加 <code>-h</code> 默认走 socket。远程连接要走网络，指定主机和端口：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mysql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 192.168.1.10</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -P</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3306</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ops</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span></span></code></pre></div><p>但默认 root 只能本机连（<code>root@localhost</code>），远程连不上。要远程连得建允许远程的账号——这是下一篇账号权限的内容。</p><h2 id="八、新装实例的基础安全" tabindex="-1">八、新装实例的基础安全 <a class="header-anchor" href="#八、新装实例的基础安全" aria-label="Permalink to &quot;八、新装实例的基础安全&quot;">​</a></h2><p>刚装好的实例有几个默认的不安全项要清理：</p><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 看现在有哪些账号</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> user, host </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> mysql</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">user</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 删匿名用户（默认可能有，能无密码连）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DROP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> USER</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> IF</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> EXISTS</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">@</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;localhost&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 删 test 库（默认权限太宽，任何人都能访问）</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">DROP</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> DATABASE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> IF</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> EXISTS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> test;</span></span></code></pre></div><p><code>&#39;&#39;@&#39;localhost&#39;</code> 是匿名账号——用户名是空串，意味着不用密码就能连进来。生产环境绝不能留。</p><h2 id="九、日常管理命令" tabindex="-1">九、日常管理命令 <a class="header-anchor" href="#九、日常管理命令" aria-label="Permalink to &quot;九、日常管理命令&quot;">​</a></h2><p>装好之后，几个天天会用的命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 检测实例是否活着</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mysqladmin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -uroot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ping</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 返回 mysqld is alive 就是活的</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查某个参数的值</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mysql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -uroot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;SHOW VARIABLES LIKE &#39;log_bin&#39;;&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查当前连接数</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mysql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -uroot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;SHOW GLOBAL STATUS LIKE &#39;Threads_connected&#39;;&quot;</span></span></code></pre></div><p><code>-e</code> 后面跟 SQL，执行完就退出，不用进交互模式。脚本里常用。</p><h2 id="装好之后" tabindex="-1">装好之后 <a class="header-anchor" href="#装好之后" aria-label="Permalink to &quot;装好之后&quot;">​</a></h2><p>MySQL 跑起来了、能连上了、基础安全做了。但里面还没有业务数据——没有库、没有表。下一篇讲怎么建库建表，把数据存进去。</p>`,73)])])}const g=i(l,[["render",h]]);export{c as __pageData,g as default};
